package main

import (
	"bufio"
	"crypto/sha1"
	"encoding/hex"
	"errors"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"
)

const (
	refsDir   = ".minigit/refs/heads"
	objectsDir = ".minigit/objects"
	indexFile = ".minigit/index"
	headFile  = ".minigit/HEAD"
)

func main() {
	if len(os.Args) < 2 {
		exit("usage: minigit <command> [<args>...]")
	}
	cmd := os.Args[1]
	switch cmd {
	case "init":
		if err := initCmd(); err != nil {
			exit(err.Error())
		}
	case "add":
		if len(os.Args) < 3 {
			exit("usage: minigit add <file>")
		}
		if err := addCmd(os.Args[2]); err != nil {
			exit(err.Error())
		}
	case "commit":
		if len(os.Args) < 3 {
			exit("usage: minigit commit <message>")
		}
		msg := strings.Join(os.Args[2:], " ")
		if err := commitCmd(msg); err != nil {
			exit(err.Error())
		}
	case "log":
		if err := logCmd(); err != nil {
			exit(err.Error())
		}
	case "checkout":
		if len(os.Args) < 3 {
			exit("usage: minigit checkout <commit>")
		}
		if err := checkoutCmd(os.Args[2]); err != nil {
			exit(err.Error())
		}
	default:
		exit("unknown command: " + cmd)
	}
}

func exit(msg string) {
	fmt.Fprintln(os.Stderr, msg)
	os.Exit(1)
}

func initCmd() error {
	if _, err := os.Stat(".minigit"); !os.IsNotExist(err) {
		return errors.New("repository already exists")
	}
	dirs := []string{
		".minigit",
		".minigit/objects",
		".minigit/refs",
		".minigit/refs/heads",
	}
	for _, d := range dirs {
		if err := os.MkdirAll(d, 0755); err != nil {
			return err
		}
	}
	if err := os.WriteFile(headFile, []byte("ref: refs/heads/master\n"), 0644); err != nil {
		return err
	}
	return nil
}

func addCmd(path string) error {
	if _, err := os.Stat(".minigit"); os.IsNotExist(err) {
		return errors.New("not a minigit repository")
	}
	data, err := os.ReadFile(path)
	if err != nil {
		return err
	}
	blob := "blob " + strconv.Itoa(len(data)) + "\x00" + string(data)
	hash := sha1.Sum([]byte(blob))
	hexHash := hex.EncodeToString(hash[:])
	dir := filepath.Join(objectsDir, hexHash[:2])
	if err := os.MkdirAll(dir, 0755); err != nil {
		return err
	}
	objPath := filepath.Join(dir, hexHash[2:])
	if err := os.WriteFile(objPath, []byte(blob), 0644); err != nil {
		return err
	}
	idx, err := readIndex()
	if err != nil {
		idx = make(map[string]string)
	}
	idx[path] = hexHash
	return writeIndex(idx)
}

func commitCmd(msg string) error {
	if _, err := os.Stat(".minigit"); os.IsNotExist(err) {
		return errors.New("not a minigit repository")
	}
	idx, err := readIndex()
	if err != nil {
		return errors.New("nothing to commit")
	}
	tree := ""
	for path := range idx {
		tree += "100644 " + path + "\x00" + idx[path] + "\n"
	}
	tree = "tree " + strconv.Itoa(len(tree)) + "\x00" + tree
	treeHash := sha1.Sum([]byte(tree))
	treeHex := hex.EncodeToString(treeHash[:])
	dir := filepath.Join(objectsDir, treeHex[:2])
	if err := os.MkdirAll(dir, 0755); err != nil {
		return err
	}
	objPath := filepath.Join(dir, treeHex[2:])
	if err := os.WriteFile(objPath, []byte(tree), 0644); err != nil {
		return err
	}
	head, _ := readHead()
	parent := ""
	if head != "" {
		parent = "\nparent " + head
	}
	author := "author user <user@example.com> " + strconv.FormatInt(time.Now().Unix(), 10) + " +0000"
	committer := "committer user <user@example.com> " + strconv.FormatInt(time.Now().Unix(), 10) + " +0000"
	commit := "commit " + strconv.Itoa(len(msg)) + "\x00" + msg + "\n" + author + "\n" + committer + parent + "\n"
	commitHash := sha1.Sum([]byte(commit))
	commitHex := hex.EncodeToString(commitHash[:])
	dir = filepath.Join(objectsDir, commitHex[:2])
	if err := os.MkdirAll(dir, 0755); err != nil {
		return err
	}
	objPath = filepath.Join(dir, commitHex[2:])
	if err := os.WriteFile(objPath, []byte(commit), 0644); err != nil {
		return err
	}
	if err := writeHead(commitHex); err != nil {
		return err
	}
	fmt.Println(commitHex)
	return nil
}

func logCmd() error {
	if _, err := os.Stat(".minigit"); os.IsNotExist(err) {
		return errors.New("not a minigit repository")
	}
	head, err := readHead()
	if err != nil {
		return errors.New("no commits yet")
	}
	for head != "" {
		obj, err := readObject(head)
		if err != nil {
			return err
		}
		lines := strings.Split(obj, "\n")
		msg := ""
		for _, line := range lines {
			if strings.HasPrefix(line, "    ") {
				msg = strings.TrimSpace(line)
				break
			}
		}
		fmt.Println("commit " + head)
		fmt.Println(msg)
		parent := ""
		for _, line := range lines {
			if strings.HasPrefix(line, "parent ") {
				parent = strings.TrimPrefix(line, "parent ")
				break
			}
		}
		if parent == "" {
			break
		}
		head = parent
		fmt.Println()
	}
	return nil
}

func checkoutCmd(commit string) error {
	if _, err := os.Stat(".minigit"); os.IsNotExist(err) {
		return errors.New("not a minigit repository")
	}
	obj, err := readObject(commit)
	if err != nil {
		return errors.New("not a commit")
	}
	if !strings.HasPrefix(obj, "commit ") {
		return errors.New("not a commit")
	}
	treeHex := ""
	lines := strings.Split(obj, "\n")
	for _, line := range lines {
		if strings.HasPrefix(line, "tree ") {
			treeHex = strings.TrimPrefix(line, "tree ")
			break
		}
	}
	if treeHex == "" {
		return errors.New("invalid commit")
	}
	tree, err := readObject(treeHex)
	if err != nil {
		return err
	}
	if !strings.HasPrefix(tree, "tree ") {
		return errors.New("invalid tree")
	}
	content := strings.SplitN(tree, "\x00", 2)[1]
	entries := strings.Split(strings.TrimSuffix(content, "\n"), "\n")
	for _, entry := range entries {
		parts := strings.Split(entry, "\x00")
		if len(parts) != 2 {
			continue
		}
		path := strings.Split(parts[0], " ")[1]
		hash := parts[1]
		data, err := readObject(hash)
		if err != nil {
			return err
		}
		if !strings.HasPrefix(data, "blob ") {
			continue
		}
		blob := strings.SplitN(data, "\x00", 2)[1]
		if err := os.WriteFile(path, []byte(blob), 0644); err != nil {
			return err
		}
	}
	return writeHead(commit)
}

func readIndex() (map[string]string, error) {
	idx := make(map[string]string)
	f, err := os.Open(indexFile)
	if err != nil {
		return nil, err
	}
	defer f.Close()
	sc := bufio.NewScanner(f)
	for sc.Scan() {
		parts := strings.SplitN(sc.Text(), " ", 2)
		if len(parts) == 2 {
			idx[parts[0]] = parts[1]
		}
	}
	return idx, sc.Err()
}

func writeIndex(idx map[string]string) error {
	f, err := os.Create(indexFile)
	if err != nil {
		return err
	}
	defer f.Close()
	for path, hash := range idx {
		if _, err := fmt.Fprintf(f, "%s %s\n", path, hash); err != nil {
			return err
		}
	}
	return nil
}

func readHead() (string, error) {
	data, err := os.ReadFile(headFile)
	if err != nil {
		return "", err
	}
	s := strings.TrimSpace(string(data))
	if strings.HasPrefix(s, "ref: ") {
		ref := strings.TrimPrefix(s, "ref: ")
		data, err := os.ReadFile(filepath.Join(".minigit", ref))
		if err != nil {
			return "", err
		}
		s = strings.TrimSpace(string(data))
	}
	return s, nil
}

func writeHead(hash string) error {
	return os.WriteFile(headFile, []byte(hash), 0644)
}

func readObject(hash string) (string, error) {
	path := filepath.Join(objectsDir, hash[:2], hash[2:])
	data, err := os.ReadFile(path)
	if err != nil {
		return "", err
	}
	return string(data), nil
}
